182→	public async fetchStylesFromMMS({
183→		page,
184→		perPage,
185→		timeoutMs,
186→	}: {
187→		page: number;
188→		perPage?: number;
189→		timeoutMs?: number;
190→	}): Promise<MMSResponse> {
191→		return this.mmsService.fetchStyles({
192→			page,
193→			...(perPage !== undefined && { perPage }),
194→			...(timeoutMs !== undefined && { timeoutMs }),
195→		});
196→	}
