198→	private checkIsProductActive({
199→		status,
200→		colors,
201→	}: {
202→		status: string;
203→		colors: MMSStyleToProcess['colors'];
204→	}): boolean {
205→		if (status === styleStatus.ACTIVE) {
206→			if (colors?.length) {
207→				return colors.some((color) => color.status === styleStatus.ACTIVE);
208→			}
209→
210→			return true;
211→		}
212→
213→		return false;
214→	}
