216→	private isProductAllowedToProcess(style: MMSStyleToProcess): boolean {
217→		const name = String(style.name);
218→		const formattedName = name.toLowerCase();
219→		const isCanadian =
220→			formattedName.includes('canada') || formattedName.includes('canadian');
221→
222→		return !isCanadian;
223→	}
