225→	private async getStoredHash({
226→		styleId,
227→	}: {
228→		styleId: number;
229→	}): Promise<IStylesHashBase['hash'] | null> {
230→		const hashRecord = await this.stylesHashService.getStyleHash({ styleId });
231→
232→		if (!hashRecord) {
233→			this.logger.debug(`No stored hash found for style ${styleId}`);
234→			return null;
235→		}
236→
237→		return hashRecord.hash;
238→	}
