240→	private async createHash({
241→		styleId,
242→		hash,
243→	}: {
244→		styleId: number;
245→		hash: string;
246→	}): Promise<void> {
247→		await this.stylesHashService.createStyleHash({
248→			data: {
249→				style_id: styleId,
250→				hash,
251→				hashing_algorithm: STYLES_HASHING_ALGORITHM,
252→			},
253→		});
254→		this.logger.debug(`Created new hash for style ${styleId}: ${hash}`);
255→	}
256→
257→	private async updateStoredHash({
258→		styleId,
259→		hash,
260→	}: {
261→		styleId: number;
262→		hash: string;
263→	}): Promise<void> {
264→		await this.stylesHashService.updateHashValue({
265→			styleId,
266→			hash,
267→			algorithm: STYLES_HASHING_ALGORITHM,
268→		});
269→		this.logger.debug(`Updated hash for style ${styleId} to ${hash}`);
270→	}
