272→	private async saveStyleToDatabase({
273→		style,
274→		allCategories,
275→		isProductActive,
276→	}: {
277→		style: MMSStyleToProcess;
278→		allCategories: MMSAllStyleCategory[];
279→		isProductActive: boolean;
280→	}): Promise<void> {
281→		try {
282→			const categoryIds = this.extractCategoryIds({ style });
283→			const categoriesWithParentsIds = this.extractCategoriesWithParents({
284→				categoryIds,
285→				allCategories,
286→			});
287→
288→			const purchasesCount =
289→				await this.productAnnualSalesService.getPurchasesCountForLatestYear({
290→					styleId: Number(style.id),
291→				});
292→
293→			const styleData = {
294→				style_id: style.id,
295→				primary_category_id: style.primary_category_id ?? 0,
296→				root_category_id: this.getRootCategoryId({ style, allCategories }),
297→				purchases_count: purchasesCount,
298→				is_active: isProductActive,
299→				name: style.name,
300→				decoration_method: style.decoration_method,
301→				features: style.features,
302→				general_comments: style.general_comments,
303→				manufacturer: style.manufacturer,
304→				minimum_quantity: style.min_qty,
305→				rating_count: style.rating_count,
306→				rating_score: Number(style.rating_score),
307→				sizes: (style.style_sizes ?? []).map((size) => size.name),
308→				style_type: style.style_type,
309→				price_level: style.price_level,
310→				primary_category_name: style.primary_category?.name ?? '',
311→				default_quote_qty: style.primary_category?.default_quote_qty ?? 1,
312→				product_type: style.product_type,
313→				style_card_image_url: this.generateStyleCardImageUrl({
314→					styleId: style.id,
315→					catalogDetailImageMd5: style.catalog_detail_image_md5,
316→				}),
317→				broad_category_names: this.getBroadCategoryNames({
318→					categories: style.categories,
319→					allCategories,
320→				}),
321→				sub_category_names: this.getStylesSubcategories({
322→					categories: style.categories,
323→					allCategories,
324→				}),
325→				turn_time: style.turntime ? Number(style.turntime.standard) : 0,
326→				rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
327→				no_minimum: style.has_singles_enabled_colors,
328→				link_path: this.calculateLink({ style, allCategories })?.path ?? '',
329→				brand: this.getBrand([style.brand]),
330→				min_qty: style.min_qty,
331→			};
332→
333→			if (!style.colors?.length) {
334→				this.logger.debug(`Style ${style.id} has no colors to save`);
335→				return;
336→			}
337→
338→			const colors = style.colors.map((color) => {
339→				const isActive = color.status === styleStatus.ACTIVE;
340→				const hasRgb = Array.isArray(color.rbgs) && color.rbgs[0];
341→				const colorRgb =
342→					hasRgb && color.rbgs[0] ? convertRGBToString({ rgb: color.rbgs[0] }) : null;
343→
344→				return {
345→					color_id: color.id,
346→					color_rgb: colorRgb,
347→					color_name: color.name,
348→					is_active: Boolean(isActive && hasRgb),
349→					image_url: color.image_url,
350→				};
351→			});
352→
353→			const defaultUnitPrices = this.getDefaultUnitPrices({ style }).map((priceData) => ({
354→				quantity: priceData.quantity,
355→				price: Number(priceData.price),
356→				regular_unit_price: priceData.regular_unit_price
357→					? Number(priceData.regular_unit_price)
358→					: null,
359→				algorithm: priceData.algorithm,
360→			}));
361→
362→			await this.stylesService.saveCompleteStyle({
363→				styleData,
364→				colors,
365→				defaultUnitPrices,
366→				categoryIds,
367→				categoriesWithParentsIds,
368→			});
369→
370→			this.logger.debug(`Successfully saved style ${style.id} to database`);
371→		} catch (error: unknown) {
372→			const err = error instanceof Error ? error : new Error(String(error));
373→			this.logger.error(`Failed to save style ${style.id} to database: ${err.message}`);
374→			throw err;
375→		}
376→	}
377→
378→	private async generateLLMFeatures({
379→		style,
380→		featuresRelatedFields,
381→	}: {
382→		style: MMSStyleToProcess;
383→		featuresRelatedFields: FeaturesRelatedFields;
384→	}): Promise<string[]> {
385→		try {
386→			const result = await withRetry({
387→				fn: () => this.OpenAIService.generateProductFeatures({ productInfo: style }),
388→				options: { retryCount: 2 },
389→			});
390→
391→			if (result.error) {
392→				this.logger.error(
393→					`Failed to generate features for style ${style.id}: ${result.error}`,
394→				);
395→				throw new Error(`Failed to generate features: ${result.error}`);
396→			}
397→
398→			return result.description ?? [];
399→		} catch (error) {
400→			const errorMessage = error instanceof Error ? error.message : String(error);
401→			const isTokenLimitError = errorMessage.includes('maximum context length');
402→
403→			if (isTokenLimitError) {
404→				this.logger.warn(
405→					`Token limit exceeded for style ${style.id}, retrying with reduced fields`,
406→				);
407→
408→				const reducedResult = await withRetry({
409→					fn: () =>
410→						this.OpenAIService.generateProductFeatures({
411→							productInfo: featuresRelatedFields as unknown as MMSStyleToProcess,
412→						}),
413→					options: { retryCount: 2 },
414→				});
415→
416→				if (reducedResult.error) {
417→					throw new Error(`Failed to generate features: ${reducedResult.error}`);
418→				}
419→
420→				this.logger.debug(
421→					`Successfully generated features for style ${style.id} using reduced fields`,
422→				);
423→				return reducedResult.description ?? [];
424→			}
425→
426→			this.logger.error(`Failed to generate features for style ${style.id}:`, error);
427→			throw error;
428→		}
429→	}
