464→	private async deleteCondensedFeatures({
465→		styleId,
466→	}: {
467→		styleId: ICondensedFeaturesBase['style_id'];
468→	}): Promise<void> {
469→		await this.condensedFeaturesService.deleteCondensedFeature({ styleId });
470→		this.logger.debug(`Deleted condensed features for style ${styleId}`);
