473→	private async updateAlgoliaIndex({
474→		style,
475→		allCategories,
476→		condensedFeatures,
477→	}: {
478→		style: MMSStyleToProcess;
479→		allCategories: MMSAllStyleCategory[];
480→		condensedFeatures?: string[];
481→	}): Promise<void> {
482→		const algoliaStyle = {
483→			objectID: String(style.id),
484→			name: style.name,
485→			primary_category_id: style.primary_category_id,
486→			brand: this.getBrand([style.brand]),
487→			condensed_features: condensedFeatures ?? [],
488→			sub_category_names: this.getStylesSubcategories({
489→				categories: style.categories,
490→				allCategories,
491→			}),
492→			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
493→			price_level: style.price_level,
494→			product_id: style.id,
495→			product_type: style.product_type,
496→			style_card_image_url: this.generateStyleCardImageUrl({
497→				styleId: style.id,
498→				catalogDetailImageMd5: style.catalog_detail_image_md5,
499→			}),
500→		};
501→
502→		const objects = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => ({
503→			...algoliaStyle,
504→			objectID: `${style['objectID']}-${suffix}`,
505→			index_suffix: suffix,
506→		}));
507→
508→		await this.algoliaService.saveObjects({ objects });
509→	}
510→
511→	private async deleteFromAlgoliaIndex({ styleId }: { styleId: number }): Promise<void> {
512→		const objectIds = ALGOLIA_OBJECT_ID_SUFFIXES.map((suffix) => `${styleId}-${suffix}`);
513→		await this.algoliaService.deleteObjects({ objectIds });
514→		this.logger.debug(`Deleted style ${styleId} from Algolia index (all suffixes)`);
515→	}
