517→	private extractFeaturesRelatedFields({
518→		style,
519→		allCategories,
520→	}: {
521→		style: MMSStyleToProcess;
522→		allCategories: MMSAllStyleCategory[];
523→	}): FeaturesRelatedFields {
524→		return {
525→			name: style.name,
526→			decoration_method: style.decoration_method,
527→			features: style.features,
528→			general_comments: style.general_comments,
529→			manufacturer: style.manufacturer,
530→			sizes: (style.style_sizes ?? []).map((size) => size.name),
531→			style_type: style.style_type,
532→			price_level: style.price_level,
533→			primary_category_name: style.primary_category?.name ?? '',
534→			product_type: style.product_type,
535→			broad_category_names: this.getBroadCategoryNames({
536→				categories: style.categories,
537→				allCategories,
538→			}),
539→			sub_category_names: this.getStylesSubcategories({
540→				categories: style.categories,
541→				allCategories,
542→			}),
543→			turn_time: style.turntime ? Number(style.turntime.standard) : 0,
544→			rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
545→			no_minimum: style.has_singles_enabled_colors ? 1 : 0,
546→		};
547→	}
548→
549→	private getDefaultUnitPrices({
550→		style,
551→	}: {
552→		style: MMSStyleToProcess;
553→	}): MMSStyleToProcess['default_unit_prices'] {
554→		return style.default_unit_prices.reduce<MMSStyleToProcess['default_unit_prices']>(
555→			(acc, pricesObj) => {
556→				if (pricesObj.algorithm !== DEFAULT_PRICING_ALGORITHM) {
557→					return acc;
558→				}
559→
560→				acc.push({
561→					quantity: pricesObj.quantity,
562→					price: pricesObj.price,
563→					algorithm: pricesObj.algorithm,
564→					regular_unit_price: pricesObj.regular_unit_price ?? null,
565→				});
566→
567→				return acc;
568→			},
569→			[],
570→		);
571→	}
