573→	private generateStyleCardImageUrl({
574→		styleId,
575→		catalogDetailImageMd5,
576→	}: {
577→		styleId: number;
578→		catalogDetailImageMd5: string | null;
579→	}): string {
580→		const basePath = '/mms/images/catalog/';
581→		const md5Path = catalogDetailImageMd5 ? `${catalogDetailImageMd5}/` : '';
582→		const stylePath = `styles/${styleId}/catalog_detail_image_medium.jpg`;
583→
584→		return `${this.mmsImagesLambdaHost}${basePath}${md5Path}${stylePath}`;
585→	}
