587→	private getBroadCategoryNames({
588→		categories,
589→		allCategories,
590→	}: {
591→		styleId?: number;
592→		categories: MMSStyleToProcess['categories'];
593→		allCategories: MMSAllStyleCategory[];
594→	}): string[] {
595→		const activeCategories = categories
596→			.map((cat) => {
597→				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
598→				if (fullCategory) {
599→					cat['parent'] = fullCategory;
600→				}
601→				return cat;
602→			})
603→			.filter((cat) => cat.active);
604→
605→		const allParents = activeCategories
606→			.map((category) => category['parent'] ?? { ...category, _id: category.id })
607→			.filter(Boolean) as MMSAllStyleCategory[];
608→
609→		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
610→			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
611→				return acc;
612→			}
613→
614→			if (!acc.some((p) => p._id === parent._id)) {
615→				acc.push(parent);
616→			}
617→
618→			return acc;
619→		}, []);
620→
621→		const names = uniqueParents
622→			.map((parent) => parent['name'])
623→			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
624→
625→		return [...new Set(names)];
626→	}
627→
628→	private getStylesSubcategories({
629→		categories,
630→		allCategories,
631→	}: {
632→		categories: MMSStyleToProcess['categories'];
633→		allCategories: MMSAllStyleCategory[];
634→	}): string[] {
635→		const activeCategories = categories.filter((cat) => cat.active && cat.parent_id);
636→
637→		const childCategories: string[] = [];
638→
639→		for (const category of activeCategories) {
640→			const hasChildren = allCategories.some((cat) => cat['parent_id'] === category.id);
641→
642→			if (!hasChildren && category.name) {
643→				childCategories.push(category.name);
644→			}
645→		}
646→
647→		return [...new Set(childCategories)];
648→	}
649→
650→	private getBrand<T>(array: (T | null | undefined)[]): T[] {
651→		return array.filter(Boolean) as T[];
652→	}
653→
654→	private calculateLink({
655→		style,
656→		allCategories,
657→	}: {
658→		style: MMSStyleToProcess;
659→		allCategories: MMSAllStyleCategory[];
660→	}): Breadcrumb | null {
661→		function urlFriendly(str: string): string {
662→			return str
663→				.toLowerCase()
664→				.replace(/&reg;/g, '®')
665→				.replace(/\//g, '-')
666→				.replace(/\s+/g, '-')
667→				.replace(/[^\+\-0-9_a-z]/g, '')
668→				.replace(/^-+|-+$/g, '')
669→				.replace(/-+/g, '-');
670→		}
671→
672→		const primaryCategory = style.primary_category;
673→
674→		if (!primaryCategory) {
675→			return null;
676→		}
677→
678→		const primaryCatParent = allCategories.find(
679→			(cat) => cat._id === primaryCategory.parent_id,
680→		);
681→
682→		const primaryCatParentName = primaryCatParent?.['name'] as string;
683→		const categoryName = primaryCategory.name;
684→
685→		const firstPartLink = !primaryCatParent
686→			? '/products'
687→			: `/products/${urlFriendly(primaryCatParentName)}`;
688→
689→		const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;
690→
691→		return {
692→			name: style.name,
693→			path: path,
694→		};
695→	}
696→
697→	private extractCategoryIds({ style }: { style: MMSStyleToProcess }): number[] {
698→		const activeCategories = style.categories.filter((cat) => cat.active);
699→		return activeCategories.map((cat) => cat.id);
700→	}
701→
702→	private extractCategoriesWithParents({
703→		categoryIds,
704→		allCategories,
705→	}: {
706→		categoryIds: number[];
707→		allCategories: MMSAllStyleCategory[];
708→	}): number[] {
709→		const allCategoryIds = new Set<number>();
710→
711→		for (const categoryId of categoryIds) {
712→			allCategoryIds.add(categoryId);
713→
714→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
715→			for (const parentId of parentIds) {
716→				allCategoryIds.add(parentId);
717→			}
718→		}
719→
720→		return Array.from(allCategoryIds).sort((a, b) => a - b);
721→	}
722→
723→	private getAllParentCategoryIds({
724→		categoryId,
725→		allCategories,
726→	}: {
727→		categoryId: number;
728→		allCategories: MMSAllStyleCategory[];
729→	}): number[] {
730→		const parents: number[] = [];
731→		const category = allCategories.find((cat) => cat._id === categoryId);
732→
733→		if (!category?.['parent_id']) {
734→			return parents;
735→		}
736→
737→		let currentParentId = category['parent_id'] as number;
738→
739→		while (currentParentId) {
740→			parents.push(currentParentId);
741→
742→			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
743→			if (!parentCategory?.['parent_id']) {
744→				break;
745→			}
746→
747→			currentParentId = parentCategory['parent_id'] as number;
748→		}
749→
750→		return parents;
751→	}
752→
753→	private getRootCategoryId({
754→		style,
755→		allCategories,
756→	}: {
757→		style: MMSStyleToProcess;
758→		allCategories: MMSAllStyleCategory[];
759→	}): number | null {
760→		if (!style.primary_category) {
761→			return null;
762→		}
763→
764→		const primaryCategory = allCategories.find(
765→			(cat) => cat._id === style.primary_category_id,
766→		);
767→		if (!primaryCategory) {
768→			return null;
769→		}
770→
771→		let currentCategory = primaryCategory;
772→		while (currentCategory['parent_id']) {
773→			const parentCategory = allCategories.find(
774→				(cat) => cat._id === currentCategory['parent_id'],
775→			);
776→			if (!parentCategory) break;
777→			currentCategory = parentCategory;
778→		}
779→
780→		return !currentCategory['parent_id'] ? currentCategory._id : null;
781→	}
782→}
