257→	generateAlgoliaRelatedProductKey({ productId }: { productId: string }): string {
258→		return `style:${productId}`;
259→	}
260→
261→	public async getRelatedProductIds({
262→		productId,
263→	}: {
264→		productId: number;
265→	}): Promise<number[]> {
266→		try {
267→			const objectIdKey = `${productId}-${ALGOLIA_OBJECT_ID_SUFFIXES[0]}`;
268→			const cacheKey = `ids:${this.generateAlgoliaRelatedProductKey({ productId: objectIdKey })}`;
269→			const cachedIds = await this.cacheService.get<number[]>({
270→				namespace: Namespaces.RELATED_ITEMS_MODEL,
271→				key: cacheKey,
272→			});
273→
274→			if (cachedIds) {
275→				this.logger.debug('Cache hit for related product IDs', {
276→					productId,
277→					objectIdKey,
278→				});
279→				await this.metricsService.incrementDailyCounter({
280→					metricType: dailyTrackingKeys.CACHE_REQUESTS,
281→				});
282→				return cachedIds;
283→			}
284→
285→			this.logger.debug('Cache miss for related product IDs', { productId, objectIdKey });
286→
287→			const results = await this.algoliaClientRecommend.getRecommendations({
288→				requests: [
289→					{
290→						indexName: this.indexName,
291→						model: 'related-products',
292→						threshold: 0,
293→						objectID: objectIdKey,
294→					},
295→				],
296→			});
297→
298→			const recommendationsHits = results.results[0]?.hits ?? [];
299→			const styleIds = recommendationsHits
300→				.map((hit) => {
301→					const productIdValue = (hit as unknown as AlgoliaRelatedProductHit).product_id;
302→					return typeof productIdValue === 'string'
303→						? Number(productIdValue)
304→						: productIdValue;
305→				})
306→				.filter((id): id is number => !isNaN(id));
307→
308→			await this.metricsService.incrementDailyCounter({
309→				metricType: dailyTrackingKeys.ALGOLIA_REQUESTS,
310→			});
311→			this.logger.debug('Fetched related product IDs from Algolia', {
312→				productId,
313→				objectIdKey,
314→				count: styleIds.length,
315→			});
316→
317→			await this.cacheService.set({
318→				namespace: Namespaces.RELATED_ITEMS_MODEL,
319→				key: cacheKey,
320→				value: styleIds,
321→				ttl: this.relatedProductsCacheTtl,
322→			});
323→
324→			return styleIds;
325→		} catch (error: unknown) {
326→			this.handleError({
327→				context: `Error fetching related product IDs from Algolia for productId ${productId}`,
328→				error,
329→			});
330→			if ((error as Error).message !== 'ObjectID does not exist') {
331→				bufferedRollbar.error({ err: error as Error, context: { productId } });
332→			}
333→			throw new Error(`Failed to fetch related product IDs for productId ${productId}`);
334→		}
335→	}
