337→	async getProductsByMultipleBrands({
338→		brands,
339→		limit = 100,
340→		categoryId,
341→	}: {
342→		brands: string[];
343→		limit?: number;
344→		categoryId?: number | undefined;
345→	}): Promise<AlgoliaRelatedProductHit[]> {
346→		try {
347→			if (brands.length === 0) {
348→				return [];
349→			}
350→
351→			const brandFilters = brands.map((brand) => `brand:"${brand}"`).join(' OR ');
352→			const suffixFilter = `index_suffix:"${ALGOLIA_OBJECT_ID_SUFFIXES[0]}"`;
353→			const categoryFilter = categoryId ? `primary_category_id:${categoryId}` : '';
354→			const combinedFilters = categoryFilter
355→				? `(${brandFilters}) AND ${categoryFilter} AND ${suffixFilter}`
356→				: `(${brandFilters}) AND ${suffixFilter}`;
357→
358→			const result = await this.algoliaClient.searchForHits({
359→				requests: [
360→					{ indexName: this.indexName, filters: combinedFilters, hitsPerPage: limit },
361→				],
362→			});
363→
364→			return (result.results[0]?.hits ?? []) as unknown as AlgoliaRelatedProductHit[];
365→		} catch (error: unknown) {
366→			this.handleError({
367→				context: `Error fetching products for brands: ${brands.join(', ')}`,
368→				error,
369→			});
370→			throw new Error(`Failed to fetch products for multiple brands`);
371→		}
372→	}
