365→	async upsertStyle({
366→		data,
367→		categoryIds,
368→		categoriesWithParentsIds,
369→	}: {
370→		data: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
371→		categoryIds?: number[];
372→		categoriesWithParentsIds?: number[];
373→	}): Promise<IStyleBase> {
374→		try {
375→			const dto = plainToInstance(BaseStyleDto, data);
376→			const errors = await validate(dto, { skipMissingProperties: true });
377→
378→			if (errors.length > 0) {
379→				this.logger.error(
380→					`Validation failed for style data: ${this.formatValidationErrors({ errors })}`,
381→				);
382→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
383→			}
384→
385→			const upsertedStyle: IStyleBase = await this.knexWrite.transaction(async (trx) => {
386→				const existing = await trx<IStyleBase>(this.tableName)
387→					.where({ style_id: data.style_id })
388→					.whereNull('deleted_at')
389→					.first();
390→
391→				if (existing) {
392→					const updateData: Record<string, unknown> = {
393→						updated_at: trx.fn.now(),
394→					};
395→
396→					Object.keys(data).forEach((key) => {
397→						if (key !== 'style_id') {
398→							if (
399→								key === 'broad_category_names' ||
400→								key === 'sub_category_names' ||
401→								key === 'brand' ||
402→								key === 'sizes'
403→							) {
404→								updateData[key] = JSON.stringify(data[key as keyof typeof data] ?? []);
405→							} else {
406→								updateData[key] = data[key as keyof typeof data];
407→							}
408→						}
409→					});
410→
411→					await trx(this.tableName)
412→						.where({ style_id: data.style_id })
413→						.whereNull('deleted_at')
414→						.update(updateData);
415→				} else {
416→					const _id = randomUUID();
417→					const insertData: Record<string, unknown> = {
418→						_id,
419→						...data,
420→						style_id: data.style_id,
421→						primary_category_id: data.primary_category_id ?? null,
422→						root_category_id: data.root_category_id ?? null,
423→						purchases_count: data.purchases_count ?? 0,
424→						is_active: data.is_active ?? true,
425→						broad_category_names: JSON.stringify(data.broad_category_names ?? []),
426→						sub_category_names: JSON.stringify(data.sub_category_names ?? []),
427→						brand: JSON.stringify(data.brand ?? []),
428→						sizes: JSON.stringify(data.sizes ?? []),
429→						created_at: trx.fn.now(),
430→						updated_at: trx.fn.now(),
